1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells with only one neighbor each (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive with exactly 2 neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it("should keep a live cell alive with exactly 3 neighbors (survival)", () => {
19	    const result = nextGeneration([[0, 1], [1, 1], [2, 1], [1, 2]]);
20	    expect(result).toContainEqual([1, 1]);
21	  });
22	  it("should kill a live cell with 4 neighbors (overpopulation)", () => {
23	    const result = nextGeneration([[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]]);
24	    expect(result).not.toContainEqual([1, 1]);
25	  });
26	  it("should bring a dead cell to life with exactly 3 live neighbors (reproduction)", () => {
27	    // ##.
28	    // #..  ->  ##.
29	    // ...      ##.
30	    // Live cells: (0,0), (1,0), (0,1). Dead cell (1,1) has 3 live neighbors -> born
31	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
32	    expect(result).toContainEqual([1, 1]);
33	  });
34	  it("should keep a block pattern unchanged (still life)", () => {
35	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
36	    const result = nextGeneration(block);
37	    const sortFn = (a: number[], b: number[]) => a[0] - b[0] || a[1] - b[1];
38	    expect(result.sort(sortFn)).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
39	  });
